using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string documentText);
}

public class DocumentSummarizer : IDocumentSummarizer
{
    public string Summarize(string documentText)
    {
        var sentences = documentText
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .ToList();

        if (sentences.Count == 0)
            return string.Empty;

        // For short documents, return the text as-is.
        const int maxSummarySentences = 3;
        if (sentences.Count <= maxSummarySentences)
            return string.Join(". ", sentences) + ".";

        // Extractive summarization: score each sentence by word frequency.
        var wordFrequency = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                wordFrequency.TryGetValue(word, out int count);
                wordFrequency[word] = count + 1;
            }
        }

        var scored = sentences
            .Select((sentence, index) => (
                Index: index,
                Sentence: sentence,
                Score: GetWords(sentence).Sum(w => wordFrequency.GetValueOrDefault(w, 0))
            ))
            .OrderByDescending(s => s.Score)
            .Take(maxSummarySentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(". ", scored) + ".";
    }

    private static IEnumerable<string> GetWords(string text) =>
        text.Split([' ', ',', ';', ':', '\t', '\n', '\r'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Select(w => w.ToLowerInvariant())
            .Where(w => w.Length > 2);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText);
        return Ok(new SummarizeResponse { Summary = summary });
    }
}

